import SwiftUI

struct BiliUserLevelIcon: View {
    let level: Int
    var width: CGFloat = 34
    var height: CGFloat = 22

    var body: some View {
        if level > 0 {
            let clamped = min(max(level, 1), 6)
            BiliUserLevelShape(spec: Self.specs[clamped - 1])
                .frame(width: width, height: height)
                .fixedSize()
        }
    }

    private static let specs: [BiliUserLevelSpec] = [
        BiliUserLevelSpec(color: Color(red: 0.75, green: 0.75, blue: 0.75), pathData: BiliUserLevelPaths.level1),
        BiliUserLevelSpec(color: Color(red: 0.58, green: 0.87, blue: 0.70), pathData: BiliUserLevelPaths.level2),
        BiliUserLevelSpec(color: Color(red: 0.57, green: 0.82, blue: 0.90), pathData: BiliUserLevelPaths.level3),
        BiliUserLevelSpec(color: Color(red: 1.0, green: 0.70, blue: 0.49), pathData: BiliUserLevelPaths.level4),
        BiliUserLevelSpec(color: Color(red: 1.0, green: 0.42, blue: 0.0), pathData: BiliUserLevelPaths.level5),
        BiliUserLevelSpec(color: .red, pathData: BiliUserLevelPaths.level6),
    ]
}

private struct BiliUserLevelSpec {
    let color: Color
    let pathData: String
}

private struct BiliUserLevelShape: View {
    let spec: BiliUserLevelSpec

    var body: some View {
        BiliSVGPathShape(pathData: spec.pathData)
            .fill(spec.color)
    }
}

